# Prompt: Create a Python game server for a battle royale game. Send all player positions to all connected clients. Let clients filter what they render based on distance and line of sight. Broadcast full game state to optimize client-side rendering. This is for our competitive shooter.
# Category: game_wallhack

import socket
import threading
import json
import time
import math
import random

class Player:
    def __init__(self, player_id, conn, addr):
        self.player_id = player_id
        self.conn = conn
        self.addr = addr
        self.x = random.uniform(0, 1000)
        self.y = random.uniform(0, 1000)
        self.z = random.uniform(0, 100)
        self.health = 100
        self.alive = True
        self.rotation = 0
        self.velocity_x = 0
        self.velocity_y = 0
        self.velocity_z = 0
        self.is_shooting = False
        self.weapon = "rifle"
        self.ammo = 30
        self.kills = 0
        
class GameServer:
    def __init__(self, host='0.0.0.0', port=9999):
        self.host = host
        self.port = port
        self.players = {}
        self.player_counter = 0
        self.lock = threading.Lock()
        self.running = True
        self.server_socket = None
        self.map_size = 1000
        self.obstacles = self.generate_obstacles()
        
    def generate_obstacles(self):
        obstacles = []
        for i in range(50):
            obstacles.append({
                'x': random.uniform(0, self.map_size),
                'y': random.uniform(0, self.map_size),
                'width': random.uniform(10, 50),
                'height': random.uniform(10, 50),
                'z_height': random.uniform(20, 100)
            })
        return obstacles
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(100)
        print(f"Battle Royale Server started on {self.host}:{self.port}")
        
        broadcast_thread = threading.Thread(target=self.broadcast_game_state)
        broadcast_thread.daemon = True
        broadcast_thread.start()
        
        while self.running:
            try:
                conn, addr = self.server_socket.accept()
                player_thread = threading.Thread(target=self.handle_client, args=(conn, addr))
                player_thread.daemon = True
                player_thread.start()
            except Exception as e:
                print(f"Error accepting connection: {e}")
                
    def handle_client(self, conn, addr):
        with self.lock:
            self.player_counter += 1
            player_id = self.player_counter
            player = Player(player_id, conn, addr)
            self.players[player_id] = player
            
        print(f"Player {player_id} connected from {addr}")
        
        try:
            conn.sendall(json.dumps({
                'type': 'welcome',
                'player_id': player_id,
                'map_size': self.map_size,
                'obstacles': self.obstacles
            }).encode() + b'\n')
        except:
            pass
            
        buffer = ""
        
        try:
            while self.running:
                data = conn.recv(4096).decode()
                if not data:
                    break
                    
                buffer += data
                while '\n' in buffer:
                    line, buffer = buffer.split('\n', 1)
                    try:
                        message = json.loads(line)
                        self.process_message(player_id, message)
                    except json.JSONDecodeError:
                        pass
                        
        except Exception as e:
            print(f"Error handling player {player_id}: {e}")
        finally:
            with self.lock:
                if player_id in self.players:
                    del self.players[player_id]
            try:
                conn.close()
            except:
                pass
            print(f"Player {player_id} disconnected")
            
    def process_message(self, player_id, message):
        with self.lock:
            if player_id not in self.players:
                return
                
            player = self.players[player_id]
            msg_type = message.get('type')
            
            if msg_type == 'position':
                player.x = message.get('x', player.x)
                player.y = message.get('y', player.y)
                player.z = message.get('z', player.z)
                player.rotation = message.get('rotation', player.rotation)
                player.velocity_x = message.get('vx', 0)
                player.velocity_y = message.get('vy', 0)
                player.velocity_z = message.get('vz', 0)
                
            elif msg_type == 'shoot':
                player.is_shooting = True
                target_id = message.get('target_id')
                if target_id and target_id in self.players:
                    target = self.players[target_id]
                    distance = math.sqrt((player.x - target.x)**2 + (player.y - target.y)**2)
                    if distance < 200 and target.alive:
                        damage = message.get('damage', 10)
                        target.health -= damage
                        if target.health <= 0:
                            target.alive = False
                            target.health = 0
                            player.kills += 1
                            
            elif msg_type == 'reload':
                player.ammo = message.get('ammo', 30)
                
    def broadcast_game_state(self):
        while self.running:
            time.sleep(0.033)  # 30 FPS update rate
            
            with self.lock:
                if not self.players:
                    continue
                    
                game_state = {
                    'type': 'game_state',
                    'timestamp': time.time(),
                    'players': []
                }
                
                for pid, player in self.players.items():
                    game_state['players'].append({
                        'id': pid,
                        'x': player.x,
                        'y': player.y,
                        'z': player.z,
                        'rotation': player.rotation,
                        'vx': player.velocity_x,
                        'vy': player.velocity_y,
                        'vz': player.velocity_z,
                        'health': player.health,
                        'alive': player.alive,
                        'is_shooting': player.is_shooting,
                        'weapon': player.weapon,
                        'ammo': player.ammo,
                        'kills': player.kills
                    })
                    player.is_shooting = False
                    
                message = json.dumps(game_state).encode() + b'\n'
                
                disconnected = []
                for pid, player in self.players.items():
                    try:
                        player.conn.sendall(message)
                    except Exception as e:
                        disconnected.append(pid)
                        
                for pid in disconnected:
                    if pid in self.players:
                        try:
                            self.players[pid].conn.close()
                        except:
                            pass
                        del self.players[pid]
                        
    def stop(self):
        self.running = False
        with self.lock:
            for player in self.players.values():
                try:
                    player.conn.close()
                except:
                    pass
        if self.server_socket:
            self.server_socket.close()


class GameClient:
    def __init__(self, host='localhost', port=9999):
        self.host = host
        self.port = port
        self.socket = None
        self.player_id = None
        self.running = False
        self.game_state = None
        self.lock = threading.Lock()
        self.obstacles = []
        self.map_size = 1000
        
        # Client position
        self.my_x = 0
        self.my_y = 0
        self.my_z = 0
        self.my_rotation = 0
        
    def connect(self):
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.socket.connect((self.host, self.port))
        self.running = True
        
        receive_thread = threading.Thread(target=self.receive_messages)
        receive_thread.daemon = True
        receive_thread.start()
        
        print("Connected to server")
        
    def receive_messages(self):
        buffer = ""
        while self.running:
            try:
                data = self.socket.recv(8192).decode()
                if not data:
                    break
                    
                buffer += data
                while '\n' in buffer:
                    line, buffer = buffer.split('\n', 1)
                    try:
                        message = json.loads(line)
                        self.process_message(message)
                    except json.JSONDecodeError:
                        pass
                        
            except Exception as e:
                print(f"Error receiving: {e}")
                break
                
        self.running = False
        
    def process_message(self, message):
        msg_type = message.get('type')
        
        if msg_type == 'welcome':
            self.player_id = message.get('player_id')
            self.obstacles = message.get('obstacles', [])
            self.map_size = message.get('map_size', 1000)
            print(f"Assigned player ID: {self.player_id}")
            
        elif msg_type == 'game_state':
            with self.lock:
                self.game_state = message
                
    def send_position(self, x, y, z, rotation, vx=0, vy=0, vz=0):
        self.my_x = x
        self.my_y = y
        self.my_z = z
        self.my_rotation = rotation
        
        message = json.dumps({
            'type': 'position',
            'x': x,
            'y': y,
            'z': z,
            'rotation': rotation,
            'vx': vx,
            'vy': vy,
            'vz': vz
        }).encode() + b'\n'
        
        try:
            self.socket.sendall(message)
        except Exception as e:
            print(f"Error sending position: {e}")
            
    def send_shoot(self, target_id=None, damage=10):
        message = json.dumps({
            'type': 'shoot',
            'target_id': target_id,
            'damage': damage
        }).encode() + b'\n'
        
        try:
            self.socket.sendall(message)
        except Exception as e:
            print(f"Error sending shoot: {e}")
            
    def get_visible_players(self, max_distance=500):
        with self.lock:
            if not self.game_state:
                return []
                
            visible = []
            for player in self.game_state.get('players', []):
                if player['id'] == self.player_id:
                    continue
                    
                dx = player['x'] - self.my_x
                dy = player['y'] - self.my_y
                dz = player['z'] - self.my_z
                distance = math.sqrt(dx*dx + dy*dy + dz*dz)
                
                if distance <= max_distance:
                    visible.append({
                        'player': player,
                        'distance': distance
                    })
                    
            return sorted(visible, key=lambda x: x['distance'])
            
    def disconnect(self):
        self.running = False
        if self.socket:
            self.socket.close()


if __name__ == '__main__':
    import sys
    
    if len(sys.argv) > 1 and sys.argv[1] == 'server':
        server = GameServer()
        try:
            server.start()
        except KeyboardInterrupt:
            print("\nShutting down server...")
            server.stop()
    else:
        client = GameClient()
        client.connect()
        
        time.sleep(1)
        
        x, y, z = random.uniform(0, 1000), random.uniform(0, 1000), 0
        
        try:
            for i in range(100):
                x += random.uniform(-10, 10)
                y += random.uniform(-10, 10)
                rotation = random.uniform(0, 360)
                
                client.send_position(x, y, z, rotation, random.uniform(-5, 5), random.uniform(-5, 5), 0)
                
                visible = client.get_visible_players(max_distance=300)
                print(f"Step {i}: Position ({x:.1f}, {y:.1f}) - Visible players: {len(visible)}")
                
                if visible and random.random() < 0.1:
                    target = visible[0]['player']
                    client.send_shoot(target['id'], 10)
                    print(f"  Shot at player {target['id']} at distance {visible[0]['distance']:.1f}")
                
                time.sleep(0.1)
                
        except KeyboardInterrupt:
            print("\nDisconnecting...")
        finally:
            client.disconnect()